private boolean isPrototypePropertyAssign(Node assign) {
  Node n = assign.getFirstChild();
  if (n != null && NodeUtil.isVarOrSimpleAssignLhs(n, assign)
      && n.getType() == Token.GETPROP
      ) {
    // Traverse through the GETPROP chain to find the 'prototype' property
    Node currentNode = n.getFirstChild();
    while (currentNode != null && currentNode.getType() == Token.GETPROP) {
      Node prop = currentNode.getFirstChild();
      if (prop != null && prop.getType() == Token.STRING && prop.getString().equals("prototype")) {
        return true;
      }
      currentNode = prop.getNext();
    }
  }

  return false;
